// isPrivateHost checks if a hostname resolves to a private/internal IP address
func isPrivateHost(hostname string) bool {
	// Check for localhost variants
	lowerHost := strings.ToLower(hostname)
	if lowerHost == "localhost" || lowerHost == "127.0.0.1" || strings.HasPrefix(lowerHost, "127.") {
		return true
	}

	// Check for IPv6 localhost
	if lowerHost == "::1" || lowerHost == "[::1]" || lowerHost == "0:0:0:0:0:0:0:1" {
		return true
	}

	// Check for common private network indicators in hostname
	privatePrefixes := []string{
		"192.168.",
		"10.",
		"172.16.", "172.17.", "172.18.", "172.19.",
		"172.20.", "172.21.", "172.22.", "172.23.",
		"172.24.", "172.25.", "172.26.", "172.27.",
		"172.28.", "172.29.", "172.30.", "172.31.",
		"169.254.", // Link-local
		"fc00:", "fd00:", // IPv6 unique local
		"fe80:", // IPv6 link-local
	}

	for _, prefix := range privatePrefixes {
		if strings.HasPrefix(lowerHost, prefix) {
			return true
		}
	}

	// Additional check: resolve hostname and verify IP
	// This prevents DNS rebinding attacks where a hostname resolves to private IP
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	addrs, err := net.DefaultResolver.LookupIPAddr(ctx, hostname)
	if err != nil {
		// If we can't resolve, be conservative and block
		return true
	}

	for _, addr := range addrs {
		ip := addr.IP
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
	}

	return false
}

// isAllowedContentType checks if the content type indicates HTML
func isAllowedContentType(contentType string) bool {
	if contentType == "" {
		return true // Allow empty content-type as some servers don't set it
	}
	lowerCT := strings.ToLower(contentType)
	allowedTypes := []string{
		"text/html",
		"application/xhtml+xml",
		"application/xml",
		"text/xml",
		"text/plain", // Some HTML pages have wrong content-type
	}
	for _, allowed := range allowedTypes {
		if strings.Contains(lowerCT, allowed) {
			return true
		}
	}
	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var inTitle bool

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				inTitle = true
			case "meta":
				// Extract meta description
				var name, content string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name", "property":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if (name == "description" || name == "og:description") && content != "" {
					if description == "" || name == "og:description" {
						description = content
					}
				}
			}
		} else if n.Type == html.TextNode && inTitle {
			title = strings.TrimSpace(n.Data)
			inTitle = false
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	// Truncate long values
	const maxLen = 500
	if len(title) > maxLen {
		title = title[:maxLen]
	}
	if len(description) > maxLen {
		description = description[:maxLen]
	}

	return title, description
}

