	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP status: %d", resp.StatusCode)})
	}

	// Limit reading to prevent memory issues
	bodyReader := io.LimitReader(resp.Body, 1<<20) // 1MB limit

	doc, err := html.Parse(bodyReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse HTML"})
	}

	preview := extractPreview(doc)

	return ctx.JSON(http.StatusOK, preview)
}

func extractPreview(n *html.Node) URLPreviewResponse {
	var result URLPreviewResponse
	var traverse func(*html.Node)

	traverse = func(node *html.Node) {
		if node.Type == html.ElementNode {
			switch node.Data {
			case "title":
				if node.FirstChild != nil && result.Title == "" {
					result.Title = strings.TrimSpace(node.FirstChild.Data)
