	privateRanges := []string{
		"10.",     // 10.0.0.0/8
		"172.16.", // 172.16.0.0/12
		"172.17.",
		"172.18.",
		"172.19.",
		"172.20.",
		"172.21.",
		"172.22.",
		"172.23.",
		"172.24.",
