		"172.26.",
		"172.27.",
		"172.28.",
		"172.29.",
		"172.30.",
		"172.31.",
		"192.168.", // 192.168.0.0/16
		"169.254.", // Link-local
	}

	for _, prefix := range privateRanges {
		if strings.HasPrefix(hostname, prefix) {
			return false
		}
	}

	// Block IPv6 private/link-local
	if strings.HasPrefix(hostname, "fc") || strings.HasPrefix(hostname, "fd") ||
		strings.HasPrefix(hostname, "fe80:") || strings.HasPrefix(hostname, "ff02:") {
		return false
	}

	return true
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string

	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
