	}

	// Create HTTP client with 3 second timeout
	httpClient := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context for additional timeout control
	reqCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(reqCtx, http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to create request"})
	}

	// Set a user agent to avoid being blocked by some servers
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.0")

	resp, err := httpClient.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to fetch URL: " + resp.Status})
	}

	// Limit reading to prevent memory issues
	bodyReader := io.LimitReader(resp.Body, 1*1024*1024) // 1MB limit

	doc, err := html.Parse(bodyReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse HTML"})
	}

	preview := extractPreview(doc)

	return ctx.JSON(http.StatusOK, preview)
}

func extractPreview(n *html.Node) PreviewResponse {
	var result PreviewResponse

	var traverse func(*html.Node)
	traverse = func(node *html.Node) {
		if node.Type == html.ElementNode {
			switch node.Data {
			case "title":
				if node.FirstChild != nil && result.Title == "" {
					result.Title = strings.TrimSpace(node.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range node.Attr {
