	}

	// Security: Reject URLs with userinfo (credentials)
	if parsedURL.User != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URLs with credentials are not allowed"})
	}

	// Security: Validate host to prevent SSRF attacks
	if parsedURL.Host == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL: missing host"})
	}

	// Security: Block private/internal IP addresses and localhost
	host := parsedURL.Hostname()
	if isPrivateHost(host) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Private/internal URLs are not allowed"})
	}

