	}

	// Block private IP ranges (IPv4)
	if strings.HasPrefix(hostname, "10.") ||
		strings.HasPrefix(hostname, "172.") {
		// Check for 172.16.0.0/12 range
		parts := strings.Split(hostname, ".")
		if len(parts) >= 2 {
			secondOctet := 0
			fmt.Sscanf(parts[1], "%d", &secondOctet)
			if secondOctet >= 16 && secondOctet <= 31 {
				return false
			}
		}
	}
	if strings.HasPrefix(hostname, "192.168.") {
		return false
	}

	// Block link-local addresses
	if strings.HasPrefix(hostname, "169.254.") {
		return false
	}

	// Block multicast addresses
	if strings.HasPrefix(hostname, "224.") || strings.HasPrefix(hostname, "239.") {
		return false
	}

	// Block reserved/documentation ranges
	if strings.HasPrefix(hostname, "192.0.2.") || // TEST-NET-1
		strings.HasPrefix(hostname, "198.51.100.") || // TEST-NET-2
		strings.HasPrefix(hostname, "203.0.113.") || // TEST-NET-3
		strings.HasPrefix(hostname, "240.") || // Reserved
		strings.HasPrefix(hostname, "255.") { // Broadcast
		return false
	}

	// Block common internal TLDs and sensitive domains
	blockedTLDs := []string{
		".local",
		".internal",
		".lan",
		".home",
		".corp",
		".test",
		".example",
		".invalid",
		".localhost",
	}
	for _, tld := range blockedTLDs {
		if strings.HasSuffix(hostname, tld) {
			return false
		}
	}

	return true
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var inTitle bool

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				inTitle = true
			case "meta":
				// Check for meta description
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
						name = attr.Val
					}
					if attr.Key == "property" && strings.EqualFold(attr.Val, "og:description") {
						name = "description" // Use og:description as fallback
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" && description == "" {
					description = content
				}
			}
		} else if n.Type == html.TextNode && inTitle {
			title = strings.TrimSpace(n.Data)
			inTitle = false
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	// Sanitize output to prevent XSS in JSON response
	title = sanitizeString(title)
	description = sanitizeString(description)

	return title, description
}

// sanitizeString removes control characters and limits length
func sanitizeString(s string) string {
	// Remove null bytes and control characters except whitespace
	var b strings.Builder
	for _, r := range s {
		if r == 0 {
			continue
		}
		// Allow printable chars and common whitespace
		if r >= 32 || r == '\t' || r == '\n' || r == '\r' {
			b.WriteRune(r)
		}
	}
	result := b.String()

	// Trim whitespace
	result = strings.TrimSpace(result)

	// Limit length
	const maxLen = 500
	if len(result) > maxLen {
		result = result[:maxLen]
	}

	return result
}

