	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": fmt.Sprintf("HTTP %d", resp.StatusCode)})
	}

	// Security: Limit response size to prevent memory exhaustion
	const maxBodySize = 2 * 1024 * 1024 // 2MB limit
	limitedReader := io.LimitReader(resp.Body, maxBodySize+1)
	body, err := io.ReadAll(limitedReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read response body"})
	}

	// Check if response exceeded size limit
	if int64(len(body)) > maxBodySize {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Response too large"})
	}

	// Security: Validate content type to ensure it's HTML
	contentType := resp.Header.Get("Content-Type")
	if !isAllowedContentType(contentType) {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid content type"})
	}

	title, description := extractTitleAndDescription(body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// isValidHost checks if the hostname is not a private/internal address
func isValidHost(hostname string) bool {
	hostname = strings.ToLower(strings.TrimSpace(hostname))

	// Reject empty hostnames
	if hostname == "" {
		return false
	}

	// Reject IP addresses and localhost variants
	if isPrivateOrLocalhost(hostname) {
		return false
	}

	return true
}

// isPrivateOrLocalhost checks if hostname is a private IP or localhost
func isPrivateOrLocalhost(hostname string) bool {
	// Check for localhost variants
	localhostNames := []string{"localhost", "127.0.0.1", "::1", "0.0.0.0"}
	for _, name := range localhostNames {
		if hostname == name || strings.HasPrefix(hostname, name+".") {
			return true
		}
	}

	// Check for private IP ranges (simplified check)
	// IPv4 private ranges
	privatePrefixes := []string{
		"10.",     // 10.0.0.0/8
		"172.16.", // 172.16.0.0/12 (simplified)
		"172.17.",
		"172.18.",
		"172.19.",
		"172.20.",
		"172.21.",
		"172.22.",
		"172.23.",
		"172.24.",
		"172.25.",
		"172.26.",
		"172.27.",
		"172.28.",
		"172.29.",
		"172.30.",
		"172.31.",
		"192.168.", // 192.168.0.0/16
		"169.254.", // Link-local
		"127.",     // Loopback
		"::1",
		"fc00:",    // IPv6 unique local
		"fe80:",    // IPv6 link-local
	}

	for _, prefix := range privatePrefixes {
		if strings.HasPrefix(hostname, prefix) {
			return true
		}
	}

	// Check for pure IP addresses (simple heuristic)
	// If it looks like an IP address, reject it for safety
	if isIPAddress(hostname) {
		return true
	}

	return false
}

// isIPAddress checks if the string looks like an IP address
func isIPAddress(s string) bool {
	// Simple check: if it contains only digits and dots/colons, likely an IP
	hasDigit := false
	for _, r := range s {
		if r >= '0' && r <= '9' {
			hasDigit = true
		} else if r != '.' && r != ':' && r != '%' {
			return false
		}
	}
	return hasDigit
}

// isAllowedContentType checks if the content type is acceptable HTML
func isAllowedContentType(contentType string) bool {
	allowedTypes := []string{
		"text/html",
		"application/xhtml+xml",
		"application/xml",
		"text/plain", // Some servers return this incorrectly
	}

	contentType = strings.ToLower(strings.TrimSpace(contentType))
	// Remove charset suffix if present
	if idx := strings.Index(contentType, ";"); idx != -1 {
		contentType = strings.TrimSpace(contentType[:idx])
	}

	for _, allowed := range allowedTypes {
		if strings.HasPrefix(contentType, allowed) {
			return true
		}
	}

	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && title == "" {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name", "property":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if (name == "description" || name == "og:description") && description == "" {
					description = strings.TrimSpace(content)
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	// Truncate long strings to prevent abuse
	const maxLen = 500
	title = truncateString(title, maxLen)
	description = truncateString(description, maxLen)

	return title, description
}

func truncateString(s string, maxLen int) string {
	if len(s) > maxLen {
		return s[:maxLen]
	}
	return s
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

