// isPrivateHost checks if the hostname refers to private/internal addresses
func isPrivateHost(host string) bool {
	host = strings.ToLower(host)

	// Check for localhost variants
	if host == "localhost" || host == "127.0.0.1" || host == "::1" || host == "0.0.0.0" {
		return true
	}

	// Check for IPv6 loopback
	if strings.HasPrefix(host, "[::1]") || host == "::1" {
		return true
	}

	// Check for link-local addresses
	if strings.HasPrefix(host, "fe80:") || strings.HasPrefix(host, "[fe80:") {
		return true
	}

	// Check common internal TLDs and patterns
	internalPatterns := []string{
		".local",
		".internal",
		".private",
		".corp",
		".home",
		".lan",
		".intranet",
	}
	for _, pattern := range internalPatterns {
		if strings.HasSuffix(host, pattern) {
			return true
		}
	}

	// Check for raw IPv4 addresses that might be private
	if isPrivateIPv4String(host) {
		return true
	}

	return false
}

// isPrivateIPv4String checks if a string represents a private IPv4 address
func isPrivateIPv4String(s string) bool {
	// Remove port if present
	if idx := strings.LastIndex(s, ":"); idx != -1 {
		s = s[:idx]
	}
	// Remove brackets for IPv6
	s = strings.Trim(s, "[]")

	ip := net.ParseIP(s)
	if ip == nil {
		return false
	}
	return isPrivateIP(ip)
}

// isPrivateIP checks if an IP address is private
func isPrivateIP(ip net.IP) bool {
	// Convert to IPv4 if possible
	if ip4 := ip.To4(); ip4 != nil {
		ip = ip4
	}

	// Private IPv4 ranges
	privateRanges := []struct {
		start net.IP
		end   net.IP
	}{
		{net.ParseIP("10.0.0.0"), net.ParseIP("10.255.255.255")},
		{net.ParseIP("172.16.0.0"), net.ParseIP("172.31.255.255")},
		{net.ParseIP("192.168.0.0"), net.ParseIP("192.168.255.255")},
		{net.ParseIP("127.0.0.0"), net.ParseIP("127.255.255.255")},
		{net.ParseIP("169.254.0.0"), net.ParseIP("169.254.255.255")}, // Link-local
		{net.ParseIP("0.0.0.0"), net.ParseIP("0.255.255.255")},
	}

	for _, r := range privateRanges {
		if bytes.Compare(ip, r.start) >= 0 && bytes.Compare(ip, r.end) <= 0 {
			return true
		}
	}

	// IPv6 loopback and unique local addresses
	if ip.To16() != nil && ip.To4() == nil {
		// ::1/128
		if ip.Equal(net.ParseIP("::1")) {
			return true
		}
		// fc00::/7 (unique local addresses)
		if len(ip) == 16 && (ip[0]&0xfe) == 0xfc {
			return true
		}
		// fe80::/10 (link-local)
		if len(ip) == 16 && (ip[0] == 0xfe && (ip[1]&0xc0) == 0x80) {
			return true
		}
	}

	return false
}

// isAllowedContentType checks if the content type is safe to process
func isAllowedContentType(contentType string) bool {
	if contentType == "" {
		return true // Allow empty content-type as some servers don't set it
	}
	ct := strings.ToLower(contentType)
	allowedTypes := []string{
		"text/html",
		"application/xhtml+xml",
		"application/xml",
		"text/plain",
	}
	for _, t := range allowedTypes {
		if strings.Contains(ct, t) {
			return true
		}
	}
	return false
}

func extractTitleAndDescription(htmlContent []byte) (string, string) {
	var title, description string
	inTitle := false

	tokenizer := html.NewTokenizer(strings.NewReader(string(htmlContent)))

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			return strings.TrimSpace(title), strings.TrimSpace(description)
		case html.StartTagToken, html.SelfClosingTagToken:
			t := tokenizer.Token()
			tagName := strings.ToLower(t.Data)

			switch tagName {
			case "title":
				inTitle = true
			case "meta":
				var name, content string
				for _, attr := range t.Attr {
					attrKey := strings.ToLower(attr.Key)
					if attrKey == "name" {
						name = strings.ToLower(attr.Val)
					} else if attrKey == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		case html.TextToken:
			if inTitle {
				title = tokenizer.Token().Data
				inTitle = false
			}
		case html.EndTagToken:
			if strings.ToLower(tokenizer.Token().Data) == "title" {
				inTitle = false
			}
		}
	}
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Logger.Fatal(e.Start(":8080"))
}

