)

type PreviewRequest struct {
	URL string `json:"url"`
}

type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "url is required"})
	}

	// Create HTTP client with 3 second timeout
	httpClient := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create context with 3 second timeout for the request
	requestCtx, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	httpReq, err := http.NewRequestWithContext(requestCtx, http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to create request"})
	}

	// Set a user agent to avoid being blocked
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	resp, err := httpClient.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "non-ok status from target URL"})
	}

	// Limit reading to prevent memory issues
	bodyReader := io.LimitReader(resp.Body, 10*1024*1024) // 10MB limit

	doc, err := html.Parse(bodyReader)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "failed to parse HTML"})
	}

	preview := extractPreview(doc)

	return ctx.JSON(http.StatusOK, preview)
}

func extractPreview(n *html.Node) PreviewResponse {
	var result PreviewResponse
	var traverse func(*html.Node)
	inHead := false

	traverse = func(node *html.Node) {
