					}
					if property == "og:title" && result.Title == "" {
						result.Title = strings.TrimSpace(content)
					}
				}
			}
		}

		for c := node.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(n)
	return result
